from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler
from datetime import datetime

app = Flask(__name__)

handler = RotatingFileHandler("application.log", maxBytes=10 * 1024 * 1024, backupCount=5)
handler.setLevel(logging.INFO)
formatter = logging.Formatter("%(asctime)s %(levelname)s %(message)s")
handler.setFormatter(formatter)
app.logger.setLevel(logging.INFO)
app.logger.addHandler(handler)
app.logger.propagate = False

USERS = {
    "admin": {"password": "admin123", "email": "admin@example.com"},
    "user": {"password": "password", "email": "user@example.com"},
}

def client_ip():
    xff = request.headers.get("X-Forwarded-For", "")
    if xff:
        return xff.split(",")[0].strip()
    return request.remote_addr or ""

@app.post("/login")
def login():
    data = request.get_json(silent=True) or {}
    username = str(data.get("username", "") or "")
    password = str(data.get("password", "") or "")
    email = str(data.get("email", "") or "")
    ip = client_ip()
    user_agent = request.headers.get("User-Agent", "")

    app.logger.info(
        'LOGIN_ATTEMPT username="%s" password="%s" email="%s" ip="%s" user_agent="%s"',
        username,
        password,
        email,
        ip,
        user_agent,
    )

    user = USERS.get(username)
    if not user:
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    if email and email != user.get("email"):
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    if password != user.get("password"):
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    token = f"debug-token-{username}-{int(datetime.utcnow().timestamp())}"
    return jsonify({"ok": True, "token": token})

@app.get("/health")
def health():
    return jsonify({"ok": True})

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000, debug=False)